(7, 1, '2026-03-31 23:11:26', '2026-03-31 21:11:26', '@media (min-width: 691px) and (max-width: 1000px) {\n	.final-sale-home-cta [data-products] {\n		--shop-columns: repeat(3, minmax(0, 1fr))\n	}\n}\n\n.final-sale-home-cta .product {\n	--theme-text-color: rgba(255, 255, 255, 0.5);\n	--theme-heading-color: #fff;\n}', 'blocksy', '', 'publish', 'closed', 'closed', '', 'blocksy', '', '', '2026-03-31 23:11:26', '2026-03-31 21:11:26', '', 0, 'http://localhost/mipagina/2026/03/31/blocksy/', 0, 'custom_css', '', 0),
(8, 1, '2026-03-31 23:11:26', '2026-03-31 21:11:26', '@media (min-width: 691px) and (max-width: 1000px) {\n	.final-sale-home-cta [data-products] {\n		--shop-columns: repeat(3, minmax(0, 1fr))\n	}\n}\n\n.final-sale-home-cta .product {\n	--theme-text-color: rgba(255, 255, 255, 0.5);\n	--theme-heading-color: #fff;\n}', 'blocksy', '', 'inherit', 'closed', 'closed', '', '7-revision-v1', '', '', '2026-03-31 23:11:26', '2026-03-31 21:11:26', '', 7, 'http://localhost/mipagina/?p=8', 0, 'revision', '', 0);
