iv class=\"wp-block-stackable-button-group stk-block-button-group stk-block stk-c36310e\" data-block-id=\"c36310e\"><style>.stk-c36310e .stk-inner-blocks{column-gap:5px !important;row-gap:5px !important;}</style><div class=\"stk-row stk-inner-blocks has-text-align-center-tablet stk-block-content stk-button-group\"><!-- wp:stackable/button {\"uniqueId\":\"fbdf709\",\"buttonPadding\":{\"top\":15,\"right\":30,\"bottom\":15,\"left\":30},\"fontWeight\":\"700\",\"textTransform\":\"uppercase\"} -->\n<div class=\"wp-block-stackable-button stk-block-button stk-block stk-fbdf709\" data-block-id=\"fbdf709\"><style>.stk-fbdf709 .stk-button{padding-top:15px !important;padding-right:30px !important;padding-bottom:15px !important;padding-left:30px !important;}.stk-fbdf709 .stk-button__inner-text{font-weight:700 !important;text-transform:uppercase !important;}</style><a class=\"stk-link stk-button stk--hover-effect-darken\" href=\"https://startersites.io/blocksy/garderobe/?page_id=81\"><span class=\"stk-button__inner-text\">Shop Now</span></a></div>\n<!-- /wp:stackable/button --></div></div>\n<!-- /wp:stackable/button-group --></div></div></div>\n<!-- /wp:stackable/column -->\n\n<!-- wp:stackable/column {\"uniqueId\":\"abfc6ec\",\"columnWidth\":60,\"columnAdjacentCount\":2,\"columnSpacing\":{\"top\":0,\"right\":0,\"bottom\":0,\"left\":0},\"columnWidthTablet\":100,\"columnAdjacentCountTablet\":1} -->\n<div class=\"wp-block-stackable-column stk-block-column stk-column stk-block stk-abfc6ec\" data-block-id=\"abfc6ec\"><style>.stk-abfc6ec-container{margin-top:0px !important;margin-right:0px !important;margin-bottom:0px !important;margin-left:0px !important;}@media screen and (min-width: 768px){.stk-abfc6ec {flex:var(--stk-flex-grow, 1) 1 calc(60% - var(--stk-column-gap, 0px) * 1 / 2 ) !important;}}@media screen and (min-width: 768px) and (max-width: 1023px){.stk-abfc6ec {flex:var(--stk-flex-grow, 1) 1 calc(100% - var(--stk-column-gap, 0px) * 0 / 1 ) !important;}}</style><div class=\"st